public class Main {
    public static void main(String[] args) {
        int number = 29;
        boolean isPrime = number > 1;
        for (int i = 2; i < number; i++) {
            if (number % i == 0) {
                isPrime = false;
            }
        }
        System.out.println(isPrime);
    }
}

