public class Main {
    public static void main(String[] args) {
        int size = 3; // half-size (the middle row has 2*size - 1 = 5 stars)
        // Your code here
    }
}

solution:
public class Main {
    public static void main(String[] args) {
        int size = 3;
        for (int i = 1; i <= size; i++) {
            for (int s = 0; s < size - i; s++) {
                System.out.print(" ");
            }
            for (int j = 0; j < 2 * i - 1; j++) {
                System.out.print("*");
            }
            System.out.println();
        }
        for (int i = size - 1; i >= 1; i--) {
            for (int s = 0; s < size - i; s++) {
                System.out.print(" ");
            }
            for (int j = 0; j < 2 * i - 1; j++) {
                System.out.print("*");
            }
            System.out.println();
        }
    }
}
